<script setup lang="ts">import { ref, onMounted } from 'vue'import { ElMessage } from 'element-plus'import { parseResponseJson } from '@/utils/parseApiResponse'interface FileRecord {  filename: string  status: string  page_count: number  file_id: string}interface RAGASMetrics {  retrieval: {    recall: number    precision: number    mrr: number  }  context: {    relevance: number    accuracy: number    coverage: number  }  generation: {    faithfulness: number    relevance: number    completeness: number  }  performance: {    avg_response_ms: number    p95_response_ms: number    throughput: number  }}const files = ref<FileRecord[]>([])const health = ref<any>(null)const loading = ref(false)const ragasMetrics = ref<RAGASMetrics>({  retrieval: { recall: 85, precision: 92, mrr: 0.88 },  context: { relevance: 89, accuracy: 91, coverage: 87 },  generation: { faithfulness: 94, relevance: 96, completeness: 88 },  performance: { avg_response_ms: 1200, p95_response_ms: 2100, throughput: 45 }})// 杩涘害鏉￠鑹?const getMetricColor = (value: number) => {  if (value >= 90) return 'bg-green'  if (value >= 80) return 'bg-accent'  if (value >= 70) return 'bg-yellow-500'  return 'bg-red'}// 杩涘害鏉″搴?const getMetricWidth = (value: number) => {  return `${Math.min(value, 100)}%`}const handleRefresh = async () => {  loading.value = true  try {    const filesResponse = await fetch('/api/files')    const filesData = (await parseResponseJson(filesResponse)) as { files?: FileRecord[] }    if (!filesResponse.ok) throw new Error((filesData as any).detail || '鑾峰彇鏂囦欢鍒楄〃澶辫触')    files.value = filesData.files || []    const healthResponse = await fetch('/api/health')    const healthData = (await parseResponseJson(healthResponse)) as Record<string, unknown>    if (!healthResponse.ok) throw new Error((healthData as any).detail || '鍋ュ悍妫€鏌ュけ璐?)    health.value = healthData    // TODO: 鍚庣鎻愪緵 RAGAS 鎸囨爣鏃讹紝鏇挎崲 mock 鏁版嵁    // const ragasResponse = await fetch('http://localhost:8000/metrics/ragas')    // const ragasData = await ragasResponse.json()    // ragasMetrics.value = ragasData    ElMessage.success('鐘舵€佸凡鍒锋柊')  } catch (error: any) {    ElMessage.error(error?.message || '鍒锋柊澶辫触')  } finally {    loading.value = false  }}onMounted(() => {  handleRefresh()})</script><template>  <div class="space-y-6">    <div class="text-xs font-bold tracking-widest text-muted uppercase pb-2.5 border-b border-border-l">      RAG 绯荤粺璇勬祴浠〃鐩?    </div>    <div>      <button        @click="handleRefresh"        :disabled="loading"        class="px-4 py-2 bg-surface text-text2 font-medium rounded-md border border-border hover:bg-surface2 disabled:opacity-50 transition-colors"      >        {{ loading ? '鍒锋柊涓?..' : '鍒锋柊鐘舵€? }}      </button>    </div>    <!-- RAGAS 鎸囨爣浠〃鐩?-->    <div class="grid grid-cols-2 gap-6">      <!-- 妫€绱㈣川閲?-->      <div class="bg-white border border-border rounded-lg p-6">        <div class="flex items-center gap-2 mb-4">          <span class="text-lg">馃攳</span>          <h3 class="text-sm font-bold text-text">妫€绱㈣川閲?/h3>        </div>        <div class="space-y-4">          <div>            <div class="flex justify-between items-center mb-1">              <span class="text-xs text-text2">鍙洖鐜?(Recall)</span>              <span class="text-sm font-semibold text-accent">{{ ragasMetrics.retrieval.recall }}%</span>            </div>            <div class="w-full bg-surface2 rounded-full h-2 overflow-hidden">              <div                class="h-full transition-all duration-300"                :class="getMetricColor(ragasMetrics.retrieval.recall)"                :style="{ width: getMetricWidth(ragasMetrics.retrieval.recall) }"              ></div>            </div>          </div>          <div>            <div class="flex justify-between items-center mb-1">              <span class="text-xs text-text2">绮惧噯鐜?(Precision)</span>              <span class="text-sm font-semibold text-accent">{{ ragasMetrics.retrieval.precision }}%</span>            </div>            <div class="w-full bg-surface2 rounded-full h-2 overflow-hidden">              <div                class="h-full transition-all duration-300"                :class="getMetricColor(ragasMetrics.retrieval.precision)"                :style="{ width: getMetricWidth(ragasMetrics.retrieval.precision) }"              ></div>            </div>          </div>          <div>            <div class="flex justify-between items-center mb-1">              <span class="text-xs text-text2">MRR (Mean Reciprocal Rank)</span>              <span class="text-sm font-semibold text-accent">{{ ragasMetrics.retrieval.mrr.toFixed(2) }}</span>            </div>            <div class="w-full bg-surface2 rounded-full h-2 overflow-hidden">              <div                class="h-full transition-all duration-300"                :class="getMetricColor(ragasMetrics.retrieval.mrr * 100)"                :style="{ width: getMetricWidth(ragasMetrics.retrieval.mrr * 100) }"              ></div>            </div>          </div>        </div>      </div>      <!-- 涓婁笅鏂囧埄鐢?-->      <div class="bg-white border border-border rounded-lg p-6">        <div class="flex items-center gap-2 mb-4">          <span class="text-lg">馃摑</span>          <h3 class="text-sm font-bold text-text">涓婁笅鏂囧埄鐢?/h3>        </div>        <div class="space-y-4">          <div>            <div class="flex justify-between items-center mb-1">              <span class="text-xs text-text2">涓婁笅鏂囩浉鍏虫€?/span>              <span class="text-sm font-semibold text-accent">{{ ragasMetrics.context.relevance }}%</span>            </div>            <div class="w-full bg-surface2 rounded-full h-2 overflow-hidden">              <div                class="h-full transition-all duration-300"                :class="getMetricColor(ragasMetrics.context.relevance)"                :style="{ width: getMetricWidth(ragasMetrics.context.relevance) }"              ></div>            </div>          </div>          <div>            <div class="flex justify-between items-center mb-1">              <span class="text-xs text-text2">涓婁笅鏂囩簿鍑嗘€?/span>              <span class="text-sm font-semibold text-accent">{{ ragasMetrics.context.accuracy }}%</span>            </div>            <div class="w-full bg-surface2 rounded-full h-2 overflow-hidden">              <div                class="h-full transition-all duration-300"                :class="getMetricColor(ragasMetrics.context.accuracy)"                :style="{ width: getMetricWidth(ragasMetrics.context.accuracy) }"              ></div>            </div>          </div>          <div>            <div class="flex justify-between items-center mb-1">              <span class="text-xs text-text2">涓婁笅鏂囪鐩栫巼</span>              <span class="text-sm font-semibold text-accent">{{ ragasMetrics.context.coverage }}%</span>            </div>            <div class="w-full bg-surface2 rounded-full h-2 overflow-hidden">              <div                class="h-full transition-all duration-300"                :class="getMetricColor(ragasMetrics.context.coverage)"                :style="{ width: getMetricWidth(ragasMetrics.context.coverage) }"              ></div>            </div>          </div>        </div>      </div>      <!-- 鐢熸垚璐ㄩ噺 -->      <div class="bg-white border border-border rounded-lg p-6">        <div class="flex items-center gap-2 mb-4">          <span class="text-lg">馃幆</span>          <h3 class="text-sm font-bold text-text">鐢熸垚璐ㄩ噺</h3>        </div>        <div class="space-y-4">          <div>            <div class="flex justify-between items-center mb-1">              <span class="text-xs text-text2">绛旀蹇犲疄搴?/span>              <span class="text-sm font-semibold text-accent">{{ ragasMetrics.generation.faithfulness }}%</span>            </div>            <div class="w-full bg-surface2 rounded-full h-2 overflow-hidden">              <div                class="h-full transition-all duration-300"                :class="getMetricColor(ragasMetrics.generation.faithfulness)"                :style="{ width: getMetricWidth(ragasMetrics.generation.faithfulness) }"              ></div>            </div>          </div>          <div>            <div class="flex justify-between items-center mb-1">              <span class="text-xs text-text2">绛旀鐩稿叧鎬?/span>              <span class="text-sm font-semibold text-accent">{{ ragasMetrics.generation.relevance }}%</span>            </div>            <div class="w-full bg-surface2 rounded-full h-2 overflow-hidden">              <div                class="h-full transition-all duration-300"                :class="getMetricColor(ragasMetrics.generation.relevance)"                :style="{ width: getMetricWidth(ragasMetrics.generation.relevance) }"              ></div>            </div>          </div>          <div>            <div class="flex justify-between items-center mb-1">              <span class="text-xs text-text2">绛旀瀹屾暣鎬?/span>              <span class="text-sm font-semibold text-accent">{{ ragasMetrics.generation.completeness }}%</span>            </div>            <div class="w-full bg-surface2 rounded-full h-2 overflow-hidden">              <div                class="h-full transition-all duration-300"                :class="getMetricColor(ragasMetrics.generation.completeness)"                :style="{ width: getMetricWidth(ragasMetrics.generation.completeness) }"              ></div>            </div>          </div>        </div>      </div>      <!-- 鎬ц兘鎸囨爣 -->      <div class="bg-white border border-border rounded-lg p-6">        <div class="flex items-center gap-2 mb-4">          <span class="text-lg">鈴憋笍</span>          <h3 class="text-sm font-bold text-text">鎬ц兘鎸囨爣</h3>        </div>        <div class="space-y-4">          <div>            <div class="flex justify-between items-center mb-1">              <span class="text-xs text-text2">骞冲潎鍝嶅簲鏃堕棿</span>              <span class="text-sm font-semibold text-accent">{{ ragasMetrics.performance.avg_response_ms }}ms</span>            </div>            <div class="text-xs text-muted">瓒婁綆瓒婂ソ</div>          </div>          <div>            <div class="flex justify-between items-center mb-1">              <span class="text-xs text-text2">P95 鍝嶅簲鏃堕棿</span>              <span class="text-sm font-semibold text-accent">{{ ragasMetrics.performance.p95_response_ms }}ms</span>            </div>            <div class="text-xs text-muted">95% 璇锋眰鍦ㄦ鏃堕棿鍐呭畬鎴?/div>          </div>          <div>            <div class="flex justify-between items-center mb-1">              <span class="text-xs text-text2">鍚炲悙閲?/span>              <span class="text-sm font-semibold text-accent">{{ ragasMetrics.performance.throughput }} req/min</span>            </div>            <div class="text-xs text-muted">姣忓垎閽熻姹傛暟</div>          </div>        </div>      </div>    </div>    <!-- 鍩虹缁熻 -->    <div v-if="health" class="grid grid-cols-3 gap-4">      <div class="bg-white border border-border rounded-lg p-5 text-center">        <div class="text-3xl font-bold text-accent">{{ files.length }}</div>        <div class="text-xs text-muted mt-1">宸插叆搴撴枃妗?/div>      </div>      <div class="bg-white border border-border rounded-lg p-5 text-center">        <div class="text-3xl font-bold text-accent">{{ health.database?.ok ? 'OK' : 'FAIL' }}</div>        <div class="text-xs text-muted mt-1">鏁版嵁搴?/div>      </div>      <div class="bg-white border border-border rounded-lg p-5 text-center">        <div class="text-2xl font-bold" :class="health.status === 'ok' ? 'text-green' : 'text-red'">          {{ health.status === 'ok' ? '姝ｅ父' : '寮傚父' }}        </div>        <div class="text-xs text-muted mt-1">{{ health.status }}</div>      </div>    </div>    <!-- 宸插叆搴撴枃妗ｅ垪琛?-->    <div>      <div class="text-xs font-bold tracking-widest text-muted uppercase pb-2.5 border-b border-border-l mb-4">        宸插叆搴撴枃妗ｅ垪琛?      </div>      <div class="bg-white border border-border rounded-lg overflow-hidden">        <table class="w-full text-sm">          <thead>            <tr class="bg-surface2 border-b border-border">              <th class="px-4 py-3 text-left font-semibold text-text2">鏂囦欢鍚?/th>              <th class="px-4 py-3 text-left font-semibold text-text2">鐘舵€?/th>              <th class="px-4 py-3 text-left font-semibold text-text2">鏂囨湰鍧?/th>              <th class="px-4 py-3 text-left font-semibold text-text2">File ID</th>            </tr>          </thead>          <tbody>            <tr v-for="file in files" :key="file.file_id" class="border-b border-border-l hover:bg-surface2">              <td class="px-4 py-3 text-text">{{ file.filename }}</td>              <td class="px-4 py-3">                <span                  :class="[                    'px-2 py-1 rounded text-xs font-medium',                    file.status === 'indexed'                      ? 'bg-green/10 text-green'                      : file.status === 'parsed'                      ? 'bg-accent/10 text-accent'                      : 'bg-muted/10 text-muted'                  ]"                >                  {{ file.status }}                </span>              </td>              <td class="px-4 py-3 text-text">{{ file.chunk_count || 0 }} 鍧?/td>              <td class="px-4 py-3 text-text2 font-mono text-xs">{{ file.file_id }}</td>            </tr>            <tr v-if="files.length === 0">              <td colspan="4" class="px-4 py-8 text-center text-muted">鏆傛棤鏂囨。</td>            </tr>          </tbody>        </table>      </div>    </div>  </div></template><style scoped></style>